test('runs middleware before handler', async () => {
  const router = new Router();
  const order: string[] = [];
  router.use(async (req, next) => {
    order.push('mw1');
    return next();
  });
  router.use(async (req, next) => {
    order.push('mw2');
    return next();
  });
  router.get('/test', () => {
    order.push('handler');
    return { status: 200, headers: {}, body: 'ok' };
  });
  await router.handle({ method: 'GET', path: '/test', headers: {} });
  expect(order).toEqual(['mw1', 'mw2', 'handler']);
});

test('middleware can short-circuit', async () => {
  const router = new Router();
  router.use(async (req, next) => {
    if (!req.headers['authorization']) {
      return { status: 401, headers: {}, body: 'Unauthorized' };
    }
    return next();
  });
  router.get('/secret', () => ({ status: 200, headers: {}, body: 'secret data' }));

  const noAuth = await router.handle({ method: 'GET', path: '/secret', headers: {} });
  expect(noAuth.status).toBe(401);

  const withAuth = await router.handle({ method: 'GET', path: '/secret', headers: { authorization: 'Bearer token' } });
  expect(withAuth.status).toBe(200);
});

test('middleware can modify request', async () => {
  const router = new Router();
  router.use(async (req, next) => {
    (req as any).userId = 'user123';
    return next();
  });
  router.get('/profile', (req) => {
    return { status: 200, headers: {}, body: { userId: (req as any).userId } };
  });
  const res = await router.handle({ method: 'GET', path: '/profile', headers: {} });
  expect((res.body as any).userId).toBe('user123');
});
